(window.webpackJsonp=window.webpackJsonp||[]).push([[242],{869:function(n,t){n.exports='\x3c!-- \ntitle: 01-React配置\nsort: \n--\x3e \n\n- # React入门\n\n  ## NodeJS\n\n  > `node.js`是基于chrome v8引擎的JS运行环境\n  >\n  > 前端开发环境、服务端编程语言\n\n  ### Npm\n\n  > [npmjs](https://www.npmjs.com/)\n\n  ```powershell\n  node -v\n  node\t# 进入JS运行环境\n  \n  npm -v\n  npm init\n  npm install [-g]\t# 全局安装\n  # 换源\n  npm config set registry https://registry.npm.taobao.org\n  # 发布包时换回原来的源\n  npm config set registry https://registry.npmjs.org\n  # 发布插件\n  npm adduser | npm publish\n  \n# 使用\n  npm init\n# 保存到package.json\n  # 下次直接install\n  npm install react --save\n  ```\n  \n  ### Yarn\n\n  > `npm i yarn -g`\n  >\n  > 弥补了npm的一些缺陷\n  >\n  > [中文文档](https://yarn.bootcss.com/)\n  \n  ```powershell\n  npm i yarn@1.22.0 -g \t# 安装特定版本\n  npm upgrade yarn -g\t\t# 更新\n  \n  yarn config set registry https://registry.npm.taobao.org\n  \n  yarn -v\n  # 初始化项目\nyarn init\n  yarn isntall\nyarn add/remove # 添加依赖包\n  yarn publish\n  yarn run\n  ```\n  \n  > 搭建环境\n  \n  ```powershell\n  yarn init\nyarn add react --save\t# 添加新插件\n  yarn install\t\t# 拉取旧插件\n\n  yarn login\t\t\t# 登录\n  yarn logout\t\t\t# 登出\n  ```\n  \n  > 编辑Package\n  \n  ```json\n    "scripts": {\n      "ver": "npm -v"\n    },\n  \n  // yarn run server\n  ```\n'}}]);